mapper.select:
SELECT d.id, d.order_number, d.reagent_id, d.reagent_name, d.batch_id, d.quantity, d.operator_id, d.operator_name, d.delivery_time, d.status, d.approver_id, d.approver_name, d.approval_time, d.rejection_reason, d.remark FROM delivery_order d
d.status != 0
AND id = #{id}
AND order_number = #{orderNumber}
AND d.reagent_name LIKE CONCAT('%', #{reagentName}, '%')
AND d.operator_id = #{operatorId}
AND d.status = #{status}
ORDER BY d.id DESC
